const functions = require('@google-cloud/functions-framework');
const sgMail = require('@sendgrid/mail');
const twilio = require('twilio');

function getEnv(name, required = true) {
  const value = process.env[name];
  if (required && (!value || !String(value).trim())) {
    throw new Error(`Missing required environment variable: ${name}`);
  }
  return value;
}

function initializeClients() {
  const sendGridApiKey = getEnv('SENDGRID_API_KEY');
  const twilioAccountSid = getEnv('TWILIO_ACCOUNT_SID');
  const twilioAuthToken = getEnv('TWILIO_AUTH_TOKEN');

  sgMail.setApiKey(sendGridApiKey);
  const twilioClient = twilio(twilioAccountSid, twilioAuthToken);

  return { twilioClient };
}

const { twilioClient } = initializeClients();

async function sendEmail(payload) {
  const from = payload.from || getEnv('SENDGRID_FROM_EMAIL');
  const to = payload.to;
  const subject = payload.subject;
  const text = payload.text;
  const html = payload.html;

  if (!to || !subject || (!text && !html)) {
    throw new Error('Email requires: to, subject, and at least one of text or html');
  }

  const msg = {
    to,
    from,
    subject,
    ...(text ? { text } : {}),
    ...(html ? { html } : {}),
  };

  const [response] = await sgMail.send(msg);
  return {
    service: 'sendgrid',
    statusCode: response.statusCode,
    headers: response.headers,
    to,
    subject,
  };
}

async function sendSms(payload) {
  const from = payload.from || getEnv('TWILIO_FROM_NUMBER');
  const to = payload.to;
  const body = payload.body;

  if (!to || !body) {
    throw new Error('SMS requires: to and body');
  }

  const message = await twilioClient.messages.create({
    from,
    to,
    body,
  });

  return {
    service: 'twilio',
    sid: message.sid,
    status: message.status,
    to,
  };
}

functions.http('deliverMessage', async (req, res) => {
  res.set('Content-Type', 'application/json');

  if (req.method !== 'POST') {
    return res.status(405).send(JSON.stringify({
      error: 'Method not allowed. Use POST.',
    }));
  }

  try {
    const body = req.body || {};
    const results = {};

    if (!body.email && !body.sms) {
      return res.status(400).send(JSON.stringify({
        error: 'Request must include at least one of: email, sms',
      }));
    }

    if (body.email) {
      results.email = await sendEmail(body.email);
    }

    if (body.sms) {
      results.sms = await sendSms(body.sms);
    }

    return res.status(200).send(JSON.stringify({
      success: true,
      results,
    }));
  } catch (error) {
    const statusCode = error.code && Number.isInteger(error.code) ? error.code : 500;
    return res.status(statusCode).send(JSON.stringify({
      success: false,
      error: error.message || 'Internal server error',
    }));
  }
});